-- YCS Supabase public baseline: 2026-03-23
-- Includes: Tables, Views, Indexes, Grants (public schema only).

CREATE EXTENSION IF NOT EXISTS pgcrypto;
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- Tables
CREATE TABLE public.staff_profiles (id uuid DEFAULT gen_random_uuid() NOT NULL, user_id uuid, name text NOT NULL, email text NOT NULL, created_at timestamp with time zone DEFAULT now() NOT NULL, updated_at timestamp with time zone DEFAULT now() NOT NULL, employee_no text, CONSTRAINT staff_profiles_email_key UNIQUE (email), CONSTRAINT staff_profiles_pkey PRIMARY KEY (id), CONSTRAINT staff_profiles_user_id_fkey FOREIGN KEY (user_id) REFERENCES auth.users(id) ON DELETE CASCADE, CONSTRAINT staff_profiles_user_id_key UNIQUE (user_id)); CREATE TABLE public.projects (id uuid DEFAULT gen_random_uuid() NOT NULL, code text NOT NULL, name text NOT NULL, description text, status text DEFAULT 'active'::text NOT NULL, created_at timestamp with time zone DEFAULT now() NOT NULL, updated_at timestamp with time zone DEFAULT now() NOT NULL, CONSTRAINT projects_code_key UNIQUE (code), CONSTRAINT projects_pkey PRIMARY KEY (id)); CREATE TABLE public.tasks (id uuid DEFAULT gen_random_uuid() NOT NULL, project_id uuid NOT NULL, code text NOT NULL, name text NOT NULL, description text, status text DEFAULT 'active'::text NOT NULL, created_at timestamp with time zone DEFAULT now() NOT NULL, updated_at timestamp with time zone DEFAULT now() NOT NULL, budgeted_md numeric(6,2), CONSTRAINT tasks_pkey PRIMARY KEY (id), CONSTRAINT tasks_project_id_code_key UNIQUE (project_id, code), CONSTRAINT tasks_project_id_fkey FOREIGN KEY (project_id) REFERENCES projects(id) ON DELETE CASCADE); CREATE TABLE public.time_records (id uuid DEFAULT gen_random_uuid() NOT NULL, staff_id uuid NOT NULL, task_id uuid, record_date date NOT NULL, factory_location text NOT NULL, check_in_time timestamp with time zone NOT NULL, check_out_time timestamp with time zone, hours_worked numeric(5,2), notes text, created_at timestamp with time zone DEFAULT now() NOT NULL, updated_at timestamp with time zone DEFAULT now() NOT NULL, CONSTRAINT time_records_pkey PRIMARY KEY (id), CONSTRAINT time_records_staff_id_fkey FOREIGN KEY (staff_id) REFERENCES staff_profiles(id) ON DELETE CASCADE, CONSTRAINT time_records_task_id_fkey FOREIGN KEY (task_id) REFERENCES tasks(id) ON DELETE CASCADE); CREATE TABLE public.billing_decisions (id uuid DEFAULT gen_random_uuid() NOT NULL, decision_type text NOT NULL, is_forced_md boolean DEFAULT false NOT NULL, recommended_md numeric(3,1), final_md numeric(3,1) NOT NULL, reason text, decision_maker_id uuid, has_conflict boolean DEFAULT false NOT NULL, conflict_type text, is_conflict_resolved boolean DEFAULT false NOT NULL, conflict_resolution_notes text, is_billable boolean DEFAULT false NOT NULL, is_active boolean DEFAULT true NOT NULL, created_at timestamp with time zone DEFAULT now() NOT NULL, updated_at timestamp with time zone DEFAULT now() NOT NULL, CONSTRAINT billing_decisions_decision_maker_id_fkey FOREIGN KEY (decision_maker_id) REFERENCES staff_profiles(id), CONSTRAINT billing_decisions_pkey PRIMARY KEY (id)); CREATE TABLE public.billing_decision_records (id uuid DEFAULT gen_random_uuid() NOT NULL, billing_decision_id uuid NOT NULL, time_record_id uuid NOT NULL, created_at timestamp with time zone DEFAULT now() NOT NULL, is_active boolean DEFAULT true NOT NULL, CONSTRAINT billing_decision_records_billing_decision_id_fkey FOREIGN KEY (billing_decision_id) REFERENCES billing_decisions(id) ON DELETE CASCADE, CONSTRAINT billing_decision_records_billing_decision_id_time_record_id_key UNIQUE (billing_decision_id, time_record_id), CONSTRAINT billing_decision_records_pkey PRIMARY KEY (id), CONSTRAINT billing_decision_records_time_record_id_fkey FOREIGN KEY (time_record_id) REFERENCES time_records(id) ON DELETE CASCADE); CREATE TABLE public.project_rates (id uuid DEFAULT gen_random_uuid() NOT NULL, project_id uuid NOT NULL, year integer NOT NULL, standard_rate numeric(10,2) NOT NULL, currency text DEFAULT 'TWD'::text NOT NULL, created_at timestamp with time zone DEFAULT now() NOT NULL, updated_at timestamp with time zone DEFAULT now() NOT NULL, CONSTRAINT project_rates_pkey PRIMARY KEY (id), CONSTRAINT project_rates_project_id_fkey FOREIGN KEY (project_id) REFERENCES projects(id) ON DELETE CASCADE, CONSTRAINT project_rates_project_id_year_key UNIQUE (project_id, year)); CREATE TABLE public.final_billings (id uuid DEFAULT gen_random_uuid() NOT NULL, billing_decision_id uuid NOT NULL, project_rate_id uuid NOT NULL, billing_date date NOT NULL, md_amount numeric(3,1) NOT NULL, unit_price numeric(10,2) NOT NULL, total_amount numeric(12,2) NOT NULL, status text DEFAULT 'draft'::text NOT NULL, created_at timestamp with time zone DEFAULT now() NOT NULL, updated_at timestamp with time zone DEFAULT now() NOT NULL, CONSTRAINT final_billings_billing_decision_id_fkey FOREIGN KEY (billing_decision_id) REFERENCES billing_decisions(id) ON DELETE RESTRICT, CONSTRAINT final_billings_billing_decision_id_key UNIQUE (billing_decision_id), CONSTRAINT final_billings_pkey PRIMARY KEY (id), CONSTRAINT final_billings_project_rate_id_fkey FOREIGN KEY (project_rate_id) REFERENCES project_rates(id) ON DELETE RESTRICT);

-- Views
CREATE OR REPLACE VIEW public.staff_daily_factory_summary AS  SELECT staff_id,    record_date,    count(DISTINCT factory_location) AS distinct_factory_count,    string_agg(DISTINCT factory_location, ', '::text ORDER BY factory_location) AS factory_locations,    count(id) AS total_record_count,    sum(hours_worked) AS total_hours_worked,    array_agg(DISTINCT id ORDER BY id) AS time_record_ids   FROM time_records tr  WHERE check_out_time IS NOT NULL  GROUP BY staff_id, record_date;

CREATE OR REPLACE VIEW public.task_billing_summary AS  WITH decision_task AS (         SELECT bd.id AS billing_decision_id,            bd.final_md,            tr.task_id           FROM billing_decisions bd             JOIN billing_decision_records bdr ON bdr.billing_decision_id = bd.id             JOIN time_records tr ON tr.id = bdr.time_record_id          WHERE bd.is_active = true AND bd.is_billable = true AND tr.task_id IS NOT NULL          GROUP BY bd.id, bd.final_md, tr.task_id        ) SELECT task_id,    COALESCE(sum(final_md), 0::numeric) AS used_md   FROM decision_task  GROUP BY task_id;

CREATE OR REPLACE VIEW public.pending_billing_decisions_summary AS  SELECT tr.id AS time_record_id,    tr.staff_id,    tr.task_id,    tr.record_date,    tr.factory_location,    tr.hours_worked,    tr.check_in_time,    tr.check_out_time,    bd.id AS billing_decision_id,    bd.decision_type,    bd.has_conflict,    bd.is_conflict_resolved,    bd.is_billable,    bd.final_md,        CASE            WHEN bd.id IS NOT NULL THEN true            ELSE false        END AS has_decision,    ( SELECT COALESCE(sum(tr2.hours_worked), 0::numeric) AS "coalesce"           FROM billing_decision_records bdr2             JOIN time_records tr2 ON bdr2.time_record_id = tr2.id          WHERE bdr2.billing_decision_id = bd.id) AS merged_total_hours,    sp.name AS staff_name,    sp.employee_no AS staff_employee_no,    NULL::text AS department_name,    tr.factory_location AS work_area_code   FROM time_records tr     LEFT JOIN billing_decision_records bdr ON tr.id = bdr.time_record_id AND bdr.is_active = true     LEFT JOIN billing_decisions bd ON bdr.billing_decision_id = bd.id AND bd.is_active = true     LEFT JOIN staff_profiles sp ON tr.staff_id = sp.id  WHERE tr.check_out_time IS NOT NULL AND (bd.id IS NULL OR bd.is_billable = false);

CREATE OR REPLACE VIEW public.decided_billing_decisions_summary AS  SELECT tr.id AS time_record_id,    tr.staff_id,    tr.task_id,    tr.record_date,    tr.factory_location,    tr.hours_worked,    tr.check_in_time,    tr.check_out_time,    bd.id AS billing_decision_id,    bd.decision_type,    bd.has_conflict,    bd.is_conflict_resolved,    bd.is_billable,    bd.final_md,    true AS has_decision,    ( SELECT COALESCE(sum(tr2.hours_worked), 0::numeric) AS "coalesce"           FROM billing_decision_records bdr2             JOIN time_records tr2 ON bdr2.time_record_id = tr2.id          WHERE bdr2.billing_decision_id = bd.id) AS merged_total_hours,    sp.name AS staff_name,    sp.employee_no AS staff_employee_no,    NULL::text AS department_name,    tr.factory_location AS work_area_code,    bd.reason   FROM time_records tr     JOIN billing_decision_records bdr ON tr.id = bdr.time_record_id AND bdr.is_active = true     JOIN billing_decisions bd ON bdr.billing_decision_id = bd.id AND bd.is_active = true     LEFT JOIN staff_profiles sp ON tr.staff_id = sp.id  WHERE tr.check_out_time IS NOT NULL;

CREATE UNIQUE INDEX IF NOT EXISTS staff_profiles_pkey ON public.staff_profiles USING btree (id); CREATE UNIQUE INDEX IF NOT EXISTS staff_profiles_user_id_key ON public.staff_profiles USING btree (user_id); CREATE UNIQUE INDEX IF NOT EXISTS staff_profiles_email_key ON public.staff_profiles USING btree (email); CREATE INDEX IF NOT EXISTS idx_staff_profiles_user_id ON public.staff_profiles USING btree (user_id); CREATE INDEX IF NOT EXISTS idx_staff_profiles_email ON public.staff_profiles USING btree (email); CREATE UNIQUE INDEX IF NOT EXISTS projects_pkey ON public.projects USING btree (id); CREATE UNIQUE INDEX IF NOT EXISTS projects_code_key ON public.projects USING btree (code); CREATE INDEX IF NOT EXISTS idx_projects_code ON public.projects USING btree (code); CREATE INDEX IF NOT EXISTS idx_projects_status ON public.projects USING btree (status); CREATE UNIQUE INDEX IF NOT EXISTS tasks_pkey ON public.tasks USING btree (id); CREATE UNIQUE INDEX IF NOT EXISTS tasks_project_id_code_key ON public.tasks USING btree (project_id, code); CREATE INDEX IF NOT EXISTS idx_tasks_project_id ON public.tasks USING btree (project_id); CREATE INDEX IF NOT EXISTS idx_tasks_code ON public.tasks USING btree (code); CREATE INDEX IF NOT EXISTS idx_tasks_status ON public.tasks USING btree (status); CREATE UNIQUE INDEX IF NOT EXISTS time_records_pkey ON public.time_records USING btree (id); CREATE INDEX IF NOT EXISTS idx_time_records_staff_date ON public.time_records USING btree (staff_id, record_date); CREATE INDEX IF NOT EXISTS idx_time_records_staff_date_factory ON public.time_records USING btree (staff_id, record_date, factory_location); CREATE INDEX IF NOT EXISTS idx_time_records_task_id ON public.time_records USING btree (task_id); CREATE INDEX IF NOT EXISTS idx_time_records_check_out ON public.time_records USING btree (check_out_time) WHERE (check_out_time IS NOT NULL); CREATE UNIQUE INDEX IF NOT EXISTS uniq_time_records_import_key ON public.time_records USING btree (staff_id, record_date, factory_location, check_in_time); CREATE INDEX IF NOT EXISTS idx_billing_decisions_active ON public.billing_decisions USING btree (is_active) WHERE (is_active = true); CREATE UNIQUE INDEX IF NOT EXISTS billing_decisions_pkey ON public.billing_decisions USING btree (id); CREATE INDEX IF NOT EXISTS idx_billing_decisions_forced_md ON public.billing_decisions USING btree (is_forced_md); CREATE INDEX IF NOT EXISTS idx_billing_decisions_decision_type ON public.billing_decisions USING btree (decision_type); CREATE INDEX IF NOT EXISTS idx_billing_decisions_decision_maker ON public.billing_decisions USING btree (decision_maker_id); CREATE INDEX IF NOT EXISTS idx_billing_decisions_conflict ON public.billing_decisions USING btree (has_conflict, is_conflict_resolved) WHERE (has_conflict = true); CREATE INDEX IF NOT EXISTS idx_billing_decisions_billable ON public.billing_decisions USING btree (is_billable) WHERE (is_billable = true); CREATE UNIQUE INDEX IF NOT EXISTS billing_decision_records_pkey ON public.billing_decision_records USING btree (id); CREATE UNIQUE INDEX IF NOT EXISTS billing_decision_records_billing_decision_id_time_record_id_key ON public.billing_decision_records USING btree (billing_decision_id, time_record_id); CREATE INDEX IF NOT EXISTS idx_billing_decision_records_decision ON public.billing_decision_records USING btree (billing_decision_id); CREATE INDEX IF NOT EXISTS idx_billing_decision_records_time_record ON public.billing_decision_records USING btree (time_record_id); CREATE UNIQUE INDEX IF NOT EXISTS uniq_bdr_active_time_record ON public.billing_decision_records USING btree (time_record_id) WHERE (is_active = true); CREATE UNIQUE INDEX IF NOT EXISTS project_rates_pkey ON public.project_rates USING btree (id); CREATE UNIQUE INDEX IF NOT EXISTS project_rates_project_id_year_key ON public.project_rates USING btree (project_id, year); CREATE INDEX IF NOT EXISTS idx_project_rates_project ON public.project_rates USING btree (project_id); CREATE INDEX IF NOT EXISTS idx_project_rates_year ON public.project_rates USING btree (year); CREATE UNIQUE INDEX IF NOT EXISTS final_billings_pkey ON public.final_billings USING btree (id); CREATE UNIQUE INDEX IF NOT EXISTS final_billings_billing_decision_id_key ON public.final_billings USING btree (billing_decision_id); CREATE INDEX IF NOT EXISTS idx_final_billings_decision ON public.final_billings USING btree (billing_decision_id); CREATE INDEX IF NOT EXISTS idx_final_billings_project_rate ON public.final_billings USING btree (project_rate_id); CREATE INDEX IF NOT EXISTS idx_final_billings_date ON public.final_billings USING btree (billing_date); CREATE INDEX IF NOT EXISTS idx_final_billings_status ON public.final_billings USING btree (status);

-- Grants
GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.billing_decision_records TO anon; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.billing_decision_records TO authenticated; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.billing_decision_records TO postgres WITH GRANT OPTION; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.billing_decision_records TO service_role; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.billing_decisions TO anon; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.billing_decisions TO authenticated; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.billing_decisions TO postgres WITH GRANT OPTION; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.billing_decisions TO service_role; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.decided_billing_decisions_summary TO anon; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.decided_billing_decisions_summary TO authenticated; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.decided_billing_decisions_summary TO postgres WITH GRANT OPTION; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.decided_billing_decisions_summary TO service_role; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.final_billings TO anon; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.final_billings TO authenticated; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.final_billings TO postgres WITH GRANT OPTION; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.final_billings TO service_role; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.pending_billing_decisions_summary TO anon; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.pending_billing_decisions_summary TO authenticated; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.pending_billing_decisions_summary TO postgres WITH GRANT OPTION; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.pending_billing_decisions_summary TO service_role; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.project_rates TO anon; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.project_rates TO authenticated; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.project_rates TO postgres WITH GRANT OPTION; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.project_rates TO service_role; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.projects TO anon; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.projects TO authenticated; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.projects TO postgres WITH GRANT OPTION; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.projects TO service_role; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.staff_daily_factory_summary TO anon; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.staff_daily_factory_summary TO authenticated; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.staff_daily_factory_summary TO postgres WITH GRANT OPTION; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.staff_daily_factory_summary TO service_role; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.staff_profiles TO anon; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.staff_profiles TO authenticated; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.staff_profiles TO postgres WITH GRANT OPTION; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.staff_profiles TO service_role; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.task_billing_summary TO anon; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.task_billing_summary TO authenticated; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.task_billing_summary TO postgres WITH GRANT OPTION; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.task_billing_summary TO service_role; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.tasks TO anon; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.tasks TO authenticated; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.tasks TO postgres WITH GRANT OPTION; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.tasks TO service_role; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.time_records TO anon; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.time_records TO authenticated; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.time_records TO postgres WITH GRANT OPTION; GRANT DELETE, INSERT, REFERENCES, SELECT, TRIGGER, TRUNCATE, UPDATE ON public.time_records TO service_role;

